class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        vector<int> cnt(10);
        long long res = 0;
        if (n == 1) {
            for (int i = 1; i <= 9; ++i) {
                if (i % k == 0) ++res;
            }
            return res;
        }
        if (n % 2 == 1) {
            cnt[0] = 9;
            for (int i = 1; i <= 9; ++i) {
                cnt[i] = cnt[i - 1] + 1;
            }
            res += cnt[n - 1] * 9;
            n -= 2;
        } else {
            cnt[0] = 9;
            for (int i = 1; i <= 9; ++i) {
                cnt[i] = cnt[i - 1] * 10;
            }
            res += cnt[n - 1];
            n -= 2;
        }
        for (int i = 0; i <= n; i += 2) {
            res += cnt[i] * cnt[i];
        }
        return res * 2;
    }
};
```

